def nth_page(items, size, n):
    if not size or n < 1:
        return []
    pages = [items[i:min(len(items), i+size)] for i in range(0, len(items), size)]
    try:
        return pages[n-1]
    except IndexError:
        # Edge case: when the page number exceeds the total number of pages
        return []
